mapper.select:
select count(*) cnt from review r left outer join users u on r.user_id = u.user_id left outer join lecture l on r.lect_id = l.lect_id
l.inst_id = #{instId}
and instr(${fieldStr}, #{keyword}) != 0

select review_id, score, content, regdate, regip, lect_id, user_id, user_name, lecture_name, inst_id from ( select r.review_id, r.score, r.content, r.regdate, r.regip, r.lect_id, r.user_id, u.name as user_name, l.name as lecture_name, l.inst_id, row_number() over(order by r.regdate desc) as rnum from review r left outer join users u on r.user_id = u.user_id left outer join lecture l on r.lect_id = l.lect_id
l.inst_id = #{instId}
and instr(${fieldStr}, #{keyword}) != 0
) where rnum between #{startNum} and #{endNum}
